    // Coroutines — required for Room's Flow/suspend queries and viewModelScope
    implementation(libs.kotlinx.coroutines.android)

    // Kotlinx Serialization — used to define type-safe Navigation 2.8+ route objects
    implementation(libs.kotlinx.serialization.json)

    // Location — FusedLocationProviderClient for GPS capture on frame log
    implementation(libs.play.services.location)

    testImplementation(libs.junit)
    androidTestImplementation(libs.androidx.junit)
    androidTestImplementation(libs.androidx.espresso.core)
    androidTestImplementation(platform(libs.androidx.compose.bom))
    androidTestImplementation(libs.androidx.compose.ui.test.junit4)
    debugImplementation(libs.androidx.compose.ui.tooling)
    debugImplementation(libs.androidx.compose.ui.test.manifest)
}

package com.southsouthwest.framelog.data.db.dao

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.Query
import androidx.room.Update
import com.southsouthwest.framelog.data.db.entity.Lens
import kotlinx.coroutines.flow.Flow

@Dao
interface LensDao {

    /**
     * Search lenses by name, make, or focal length. Empty query returns all lenses.
     * Used by the gear library list and roll setup lens picker.
     */
    @Query("SELECT * FROM lenses WHERE name LIKE '%' || :query || '%' OR make LIKE '%' || :query || '%' OR CAST(focalLengthMm AS TEXT) LIKE '%' || :query || '%' ORDER BY make ASC, focalLengthMm ASC")
    fun searchLenses(query: String): Flow<List<Lens>>

    @Query("SELECT * FROM lenses WHERE id = :id")
    fun getLensById(id: Int): Flow<Lens>

    @Insert
    suspend fun insertLens(lens: Lens)

    @Update
    suspend fun updateLens(lens: Lens)

    @Delete
    suspend fun deleteLens(lens: Lens)

    /**
     * Returns all lenses compatible with a specific camera body mount type.
     * Used by roll setup to filter the lens picker to compatible lenses only.
     */
    @Query("SELECT * FROM lenses WHERE mountType = :mountType ORDER BY focalLengthMm ASC")
    fun getLensesByMountType(mountType: String): Flow<List<Lens>>
}

package com.southsouthwest.framelog.data.db.dao

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.Query
import androidx.room.Update
import com.southsouthwest.framelog.data.db.entity.Filter
import kotlinx.coroutines.flow.Flow

@Dao
interface FilterDao {

    /**
     * Search filters by name, make, or filter type. Empty query returns all filters.
     * Used by the gear library list and roll setup filter picker.
     */
    @Query("SELECT * FROM filters WHERE name LIKE '%' || :query || '%' OR make LIKE '%' || :query || '%' OR filterType LIKE '%' || :query || '%' ORDER BY filterType ASC, name ASC")
    fun searchFilters(query: String): Flow<List<Filter>>

    @Query("SELECT * FROM filters WHERE id = :id")
    fun getFilterById(id: Int): Flow<Filter>

    @Insert
    suspend fun insertFilter(filter: Filter)

    @Update
    suspend fun updateFilter(filter: Filter)

    @Delete
    suspend fun deleteFilter(filter: Filter)

    /**
     * Returns all distinct filterType values across all filters.
     * Used to populate the filter type picker — folksonomy pattern,
     * user-defined vocabulary with autocomplete from existing values.
     */
    @Query("SELECT DISTINCT filterType FROM filters ORDER BY filterType ASC")
    fun getDistinctFilterTypes(): Flow<List<String>>
}

package com.southsouthwest.framelog.data.db.dao

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.Query
import androidx.room.Update
import com.southsouthwest.framelog.data.db.entity.FilmStock
import kotlinx.coroutines.flow.Flow

@Dao
interface FilmStockDao {

    /**
     * Search film stocks by name or make, optionally including discontinued stocks.
     * Discontinued stocks are hidden by default to keep pickers clean, but still exist
     * in the database to preserve historical roll data.
     */
    @Query("SELECT * FROM film_stocks WHERE (name LIKE '%' || :query || '%' OR make LIKE '%' || :query || '%') AND (discontinued = 0 OR :includeDiscontinued = 1) ORDER BY make ASC, name ASC")
    fun searchFilmStocks(query: String, includeDiscontinued: Boolean = false): Flow<List<FilmStock>>

    @Query("SELECT * FROM film_stocks WHERE id = :id")
    fun getFilmStockById(id: Int): Flow<FilmStock>

    @Insert
    suspend fun insertFilmStock(filmStock: FilmStock)

    @Update
    suspend fun updateFilmStock(filmStock: FilmStock)

    @Delete
    suspend fun deleteFilmStock(filmStock: FilmStock)
}

package com.southsouthwest.framelog.data.db

import androidx.room.TypeConverter
import com.southsouthwest.framelog.data.db.entity.ApertureIncrements
import com.southsouthwest.framelog.data.db.entity.CameraBodyFormat
import com.southsouthwest.framelog.data.db.entity.ColorType
import com.southsouthwest.framelog.data.db.entity.FilmFormat
import com.southsouthwest.framelog.data.db.entity.RollStatus
import com.southsouthwest.framelog.data.db.entity.ShutterIncrements

/**
 * Room TypeConverters for all enum types stored as human-readable strings in SQLite.
 * Using string values (e.g. "35mm", "full") rather than ordinals makes the database
 * readable outside the app and safe against enum reordering in future refactors.
 */
class Converters {

    @TypeConverter fun fromCameraBodyFormat(value: CameraBodyFormat): String = value.value
    @TypeConverter fun toCameraBodyFormat(value: String): CameraBodyFormat = CameraBodyFormat.fromValue(value)

    @TypeConverter fun fromFilmFormat(value: FilmFormat): String = value.value
    @TypeConverter fun toFilmFormat(value: String): FilmFormat = FilmFormat.fromValue(value)

    @TypeConverter fun fromShutterIncrements(value: ShutterIncrements): String = value.value
    @TypeConverter fun toShutterIncrements(value: String): ShutterIncrements = ShutterIncrements.fromValue(value)

    @TypeConverter fun fromApertureIncrements(value: ApertureIncrements): String = value.value
    @TypeConverter fun toApertureIncrements(value: String): ApertureIncrements = ApertureIncrements.fromValue(value)

    @TypeConverter fun fromColorType(value: ColorType): String = value.value
    @TypeConverter fun toColorType(value: String): ColorType = ColorType.fromValue(value)

    @TypeConverter fun fromRollStatus(value: RollStatus): String = value.value
    @TypeConverter fun toRollStatus(value: String): RollStatus = RollStatus.fromValue(value)
}

